SELECT o.orderid, od.discount, od.unitprice, od.quantity, o.shipcountry, o.shippeddate, c.categoryname FROM orders o JOIN "order details" od ON o.orderid = od.orderid JOIN products p ON od.productid = p.productid JOIN categories c ON p.categoryid = c.categoryid WHERE (o.shipcountry = 'Germany') AND (strftime('%Y', o.shippeddate) = '1997') AND (strftime('%m', o.shippeddate) BETWEEN '01' AND '03') AND (c.categoryname = 'Beverages' OR c.categoryname = 'Condiments')
